/*
 * hardware/key_derive_vectors.h
 *
 * Canonical test vectors for cm_derive_keys() — T0.4 per-abstraction key
 * derivation.  Generated by scripts/test_key_derivation_vectors.py.
 *
 * Formula (CM_ENC_v3 / CM_MAC_v3 — spec Section 2.6):
 *   preimage  = uid_hi_BE4 || uid_lo_BE4 || ogt_utf8
 *   IKM       = SHA256(preimage)
 *   K_enc[16] = HKDF-SHA256(IKM, salt="CM_ENC_v3", info=ogt, len=16)
 *   K_mac[16] = HKDF-SHA256(IKM, salt="CM_MAC_v3", info=ogt, len=16)
 *
 * Both the C test (hardware/key_derive_test.c) and the Python test
 * (scripts/test_key_derivation_vectors.py) assert byte-for-byte agreement
 * with these values.
 */

